console.log('10 + 5 =', calc.add(10, 5));        // 15
console.log('10 - 5 =', calc.subtract(10, 5));    // 5
console.log('10 * 5 =', calc.multiply(10, 5));    // 50
console.log('10 / 5 =', calc.divide(10, 5));      // 2
