function reverseString(s) {
  return s.split('').reverse().join('');
}

// Alternative (iterative):
function reverseStringIter(s) {
  const chars = s.split('');
  let left = 0, right = chars.length - 1;
  while (left < right) {
    [chars[left], chars[right]] = [chars[right], chars[left]];
    left++;
    right--;
  }
  return chars.join('');
}

