function reverseInteger(n) {
  const sign = n < 0 ? -1 : 1;
  n = Math.abs(n);
  let result = 0;
  while (n) { result = result * 10 + (n % 10); n = Math.floor(n / 10); }
  const signed = sign * result;
  // 32-bit overflow guard (LeetCode-style)
  if (signed < -(2 ** 31) || signed > 2 ** 31 - 1) return 0;
  return signed;
}
