  const n = nums.length;
  if (n < 2 && sample) throw new RangeError('sample variance requires >= 2 data points');
  if (n < 1) throw new RangeError('variance of empty array');
  const mu = nums.reduce((a, b) => a + b, 0) / n;
  const sq = nums.reduce((acc, x) => acc + (x - mu) ** 2, 0);
